 6	  InfoCircleIcon
 7	} from '@patternfly/react-icons';
 8	import { ValidationTypes } from '../../types/IstioObjects';
 9	import { Text, TextVariants } from '@patternfly/react-core';
10	import { PFColors } from 'components/Pf/PfColors';
