14	const validationStyle = kialiStyle({
15	  textAlign: 'left',
16	  $nest: {
17	    '&:last-child p': {
18	      margin: 0
19	    }
20	  }
21	});
22	
23	type ValidationProps = {
24	  message?: string;
25	  messageColor?: boolean;
26	  severity: ValidationTypes;
27	};
28	
29	const ErrorValidation: IconProps = {
30	  color: PFColors.Danger,
31	  icon: ExclamationCircleIcon,
32	  dataTest: 'icon-error-validation'
33	};
34	
35	const WarningValidation: IconProps = {
36	  color: PFColors.Warning,
37	  icon: ExclamationTriangleIcon,
38	  dataTest: 'icon-warning-validation'
39	};
40	
41	const InfoValidation: IconProps = {
42	  color: PFColors.Info,
43	  icon: InfoCircleIcon
44	};
45	
46	const CorrectValidation: IconProps = {
47	  color: PFColors.Success,
48	  icon: CheckCircleIcon,
49	  dataTest: 'icon-correct-validation'
50	};
51	
52	const severityToValidation: { [severity: string]: IconProps } = {
53	  correct: CorrectValidation,
54	  error: ErrorValidation,
55	  info: InfoValidation,
56	  warning: WarningValidation
57	};
58	
59	export const Validation: React.FC<ValidationProps> = (props: ValidationProps) => {
60	  const validation = severityToValidation[props.severity];
61	  const severityColor = { color: validation.color };
62	  const hasMessage = !!props.message;
63	
64	  // Set styles
65	  const textStyle = props.messageColor ? severityColor : {};
66	  const iconStyle = kialiStyle(severityColor);
67	
68	  const iconProps: IconProps = {
69	    className: iconStyle,
70	    icon: validation.icon,
71	    dataTest: validation.dataTest
72	  };
73	
74	  if (hasMessage) {
75	    return (
76	      <div className={validationStyle}>
77	        <Text component={TextVariants.p} style={textStyle}>
78	          {createIcon(iconProps)} {props.message}
79	        </Text>
80	      </div>
81	    );
82	  } else {
83	    return <>{createIcon(iconProps)}</>;
84	  }
85	};

