 1	import * as React from 'react';
 2	import { shallowToJson } from 'enzyme-to-json';
 3	import { shallow } from 'enzyme';
 4	import { ValidationSummary } from '../ValidationSummary';
 5	
 6	const testScenario = (summary: any) => {
 7	  const wrapper = shallow(summary);
 8	  expect(shallowToJson(wrapper)).toBeDefined();
 9	  expect(shallowToJson(wrapper)).toMatchSnapshot();
10	};
11	
12	describe('ValidationSummary renders', () => {
13	  // Istio config validations
14	  it('success icon when all istio components are valid', () => {
15	    testScenario(<ValidationSummary id={'1'} errors={0} warnings={0} objectCount={1} type="istio" />);
16	    testScenario(<ValidationSummary id={'1'} errors={0} warnings={0} objectCount={4} type="istio" />);
17	  });
18	
19	  it('warning icon when all istio components are valid', () => {
20	    testScenario(<ValidationSummary id={'2'} errors={0} warnings={1} objectCount={1} type="istio" />);
21	    testScenario(<ValidationSummary id={'2'} errors={0} warnings={1} objectCount={3} type="istio" />);
22	  });
23	
24	  it('error icon when all istio components are valid', () => {
25	    testScenario(<ValidationSummary id={'3'} errors={1} warnings={0} objectCount={1} type="istio" />);
26	    testScenario(<ValidationSummary id={'3'} errors={1} warnings={2} objectCount={3} type="istio" />);
27	  });
28	
29	  it('N/A when all istio components are valid', () => {
30	    testScenario(<ValidationSummary id={'4'} errors={0} warnings={0} objectCount={0} type="istio" />);
31	  });
32	
33	  // Service validations
34	  it('success icon when all services are valid', () => {
35	    testScenario(<ValidationSummary id={'1'} errors={0} warnings={0} type="service" />);
